import { filter, from, map, mergeAll, mergeWith } from 'rxjs';
export const filterDefined = () => (source$) => source$.pipe(filter(v => v !== undefined), map(v => v));
/** Applies a **`job`** mapping function and then filters out all the undefined values */
export const filterMap = (job) => (source$) => source$.pipe(map(value => job(value)), filterDefined());
// Will subscribe to all passed observables with the source observable, but publish only the source observable.
export const subscribeWith = (...others) => (source$) => {
    const argsOrArgArray = (args) => args.length === 1 && Array.isArray(args[0]) ? args[0] : args;
    const others$ = argsOrArgArray(others);
    return from(others$).pipe(mergeAll(), filter(() => false), // stop all the passed observables
    map(() => undefined), mergeWith(source$) // and just publish the source
    );
};
